         difficulty:"elite",
         conceptCluster:"profit_erosion",
         primarySkill:"barriers_to_entry",
         secondarySkills:["network_effects"],
         repairSkill:"barriers_to_entry",
         commonError:"Assuming observed entry means barriers are economically unimportant",
